// Operating constraint: retain a screen-reader-readable decision trace.
// Changed case: saturate one tenant budget while another tenant remains serviceable.
function worked_http_server_ts_node_runtime_lifecycle_5(configured: boolean, dependencyReady: boolean, draining: boolean): { phase: string; admit: boolean } {
  let phase = configured ? "starting" : "configuration-failed";
  let admit = configured && dependencyReady && !draining;
  if (admit) phase = "ready";
  if (draining) {
    phase = "draining";
    admit = false;
  }
  return { phase, admit };
}

